function SocialFeedWidget() {
    const posts = [
        { id: 1, user: 'LiTreeAgent', text: 'Metaverse Hub V2.4 is live!', platform: 'twitter' },
        { id: 2, user: 'ProfitPilot', text: 'New trading signal detected...', platform: 'facebook' },
        { id: 3, user: 'StudioCreator', text: 'Just rendered a new bioluminescent node.', platform: 'instagram' },
    ];

    return (
        <div className="meta-widget social-feed">
            <div className="widget-header">SOCIAL FEED</div>
            <div className="feed-list">
                {posts.map(post => (
                    <div key={post.id} className="feed-item">
                        <div className="user">@{post.user}</div>
                        <div className="text">{post.text}</div>
                    </div>
                ))}
            </div>
        </div>
    );
}

// --- Main App ---

function App() {
  const [sessions, setSessions] = useState<Session[]>([]);
  const [currentSessionIndex, setCurrentSessionIndex] = useState<number>(-1);
  const [focusedArtifactIndex, setFocusedArtifactIndex] = useState<number | null>(null);
  const [isPreviewMode, setIsPreviewMode] = useState<boolean>(false);
  const [previewDevice, setPreviewDevice] = useState<'desktop' | 'mobile'>('desktop');

  const [inputValue, setInputValue] = useState<string>('');
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [placeholderIndex, setPlaceholderIndex] = useState(0);
  const [placeholders, setPlaceholders] = useState<string[]>(INITIAL_PLACEHOLDERS);

  const [drawerState, setDrawerState] = useState<{
      isOpen: boolean;
      mode: 'code' | 'variations' | null;
      title: string;
      data: any; 
  }>({ isOpen: false, mode: null, title: '', data: null });

  const [componentVariations, setComponentVariations] = useState<ComponentVariation[]>([]);

  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
      inputRef.current?.focus();
  }, []);

  // Cycle placeholders
  useEffect(() => {
      const interval = setInterval(() => {
          setPlaceholderIndex(prev => (prev + 1) % placeholders.length);
      }, 3000);
      return () => clearInterval(interval);
  }, [placeholders.length]);

  const handleInputChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    setInputValue(event.target.value);
  };

  const handleSendMessage = useCallback(async (manualPrompt?: string) => {
    const promptToUse = manualPrompt || inputValue;
    const trimmedInput = promptToUse.trim();

    if (!trimmedInput || isLoading) return;
    if (!manualPrompt) setInputValue('');

    setIsLoading(true);
    const baseTime = Date.now();
    const sessionId = generateId();

    const placeholderArtifacts: Artifact[] = Array(3).fill(null).map((_, i) => ({
        id: `${sessionId}_${i}`,
        styleName: 'Designing...',
        html: '',
        status: 'streaming',
    }));

    const newSession: Session = {
        id: sessionId,
        prompt: trimmedInput,
        timestamp: baseTime,
        artifacts: placeholderArtifacts
    };

    setSessions(prev => [...prev, newSession]);
    setCurrentSessionIndex(sessions.length); 
    setFocusedArtifactIndex(null); 

    try {
        const apiKey = process.env.API_KEY;
        const ai = new GoogleGenAI({ apiKey });

        const stylePrompt = `Generate 3 creative Metaverse design directions for: "${trimmedInput}". Return JSON array of 3 names.`;
        const styleResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: { role: 'user', parts: [{ text: stylePrompt }] }
        });

        let generatedStyles: string[] = ["Cybernetic Glass", "Volumetric Neon", "Brutalist Void"];
        try {
            const jsonMatch = styleResponse.text?.match(/\[[\s\S]*\]/);
            if (jsonMatch) generatedStyles = JSON.parse(jsonMatch[0]);
        } catch (e) {}

        const generateArtifact = async (artifact: Artifact, styleInstruction: string) => {
            const prompt = `Create a high-fidelity Metaverse UI widget for: "${trimmedInput}". Style: ${styleInstruction}. Return RAW HTML/CSS.`;
            const responseStream = await ai.models.generateContentStream({
                model: 'gemini-3-flash-preview',
                contents: [{ parts: [{ text: prompt }], role: "user" }],
            });

            let accumulatedHtml = '';
            for await (const chunk of responseStream) {
                accumulatedHtml += chunk.text || '';
                setSessions(prev => prev.map(sess => 
                    sess.id === sessionId ? {
                        ...sess,
                        artifacts: sess.artifacts.map(art => 
                            art.id === artifact.id ? { ...art, html: accumulatedHtml } : art
                        )
                    } : sess
                ));
            }

            const finalHtml = accumulatedHtml.replace(/```html|```/g, '').trim();
            setSessions(prev => prev.map(sess => 
                sess.id === sessionId ? {
                    ...sess,
                    artifacts: sess.artifacts.map(art => 
                        art.id === artifact.id ? { ...art, html: finalHtml, status: 'complete' } : art
                    )
                } : sess
            ));
        };

        await Promise.all(placeholderArtifacts.map((art, i) => generateArtifact(art, generatedStyles[i])));

    } catch (e) {
        console.error(e);
    } finally {
        setIsLoading(false);
    }
  }, [inputValue, isLoading, sessions.length]);

  const currentSession = sessions[currentSessionIndex];
  const focusedArtifact = currentSession?.artifacts[focusedArtifactIndex ?? -1];

  return (
    <div className={`immersive-app ${isPreviewMode ? 'full-site-preview' : ''}`}>
        {!isPreviewMode && <DottedGlowBackground color="rgba(59, 130, 246, 0.05)" glowColor="rgba(59, 130, 246, 0.2)" />}

        <AnimatePresence mode="wait">
            {!isPreviewMode ? (
                <motion.div 
                    key="editor"
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    className="editor-layer"
                >
                    <div className="stage-container">
                        {!currentSession && (
                            <div className="empty-state">
                                <h1>LiTreeLab Studio</h1>
                                <p>Prompt-to-Metaverse Generation Engine</p>
                            </div>
                        )}
                        {currentSession && (
                            <div className="artifact-grid">
                                {currentSession.artifacts.map((artifact, aIndex) => (
                                    <ArtifactCard 
                                        key={artifact.id}
                                        artifact={artifact}
                                        isFocused={focusedArtifactIndex === aIndex}
                                        onClick={() => setFocusedArtifactIndex(aIndex)}
                                    />
                                ))}
                            </div>
                        )}
                    </div>

                    <div className="floating-input-container">
                        <div className={`input-wrapper ${isLoading ? 'loading' : ''}`}>
                            <input 
                                ref={inputRef}
                                type="text" 
                                placeholder={placeholders[placeholderIndex]}
                                value={inputValue} 
                                onChange={handleInputChange} 
                                onKeyDown={e => e.key === 'Enter' && handleSendMessage()} 
                                disabled={isLoading} 
                            />
                            <button onClick={() => handleSendMessage()} disabled={isLoading} className="send-button">
                                {isLoading ? <ThinkingIcon /> : <ArrowUpIcon />}
                            </button>
                        </div>
                    </div>

                    {focusedArtifactIndex !== null && (
                        <div className="action-bar visible">
                            <button onClick={() => setFocusedArtifactIndex(null)}><GridIcon /> Grid</button>
                            <button onClick={() => setIsPreviewMode(true)}><SparklesIcon /> Full Site</button>
                            <button onClick={() => setDrawerState({ isOpen: true, mode: 'code', title: 'Code', data: focusedArtifact?.html })}><CodeIcon /> Source</button>
                        </div>
                    )}
                </motion.div>
            ) : (
                <motion.div 
                    key="preview"
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: 1, scale: 1 }}
                    exit={{ opacity: 0, scale: 1.05 }}
                    className="metaverse-dashboard"
                >
                    <nav className="dashboard-nav">
                        <div className="logo">LITREELAB</div>
                        <div className="nav-links">
                            <span className="active">HUB</span>
                            <span>STUDIO</span>
                            <span>PROFIT PILOT</span>
                            <span>VAULT</span>
                        </div>
                        <div className="user-profile">
                            <div className="status">LIVE</div>
                            <button className="exit-btn" onClick={() => setIsPreviewMode(false)}>EXIT STUDIO</button>
                        </div>
                    </nav>

                    <div className="dashboard-content">
                        <div className="sidebar-widgets">
                            <ProfitPilotWidget />
                            <SocialFeedWidget />
                            <div className="meta-widget status-card">
                                <div className="widget-header">SYSTEM LOAD</div>
                                <div className="load-meter"><div className="fill" style={{ width: '65%' }}></div></div>
                                <div className="load-text">GPU Nodes: 128 / 512</div>
                            </div>
                        </div>

                        <div className="main-viewport">
                            <div className="viewport-3d">
                                <MetaverseScene />
                                <div className="viewport-overlay">
                                    <div className="coord">X: 124.5 Y: 92.1 Z: 0.0</div>
                                </div>
                            </div>

                            <div className="gen-widgets-preview">
                                {currentSession?.artifacts.map((art, i) => (
                                    <div key={art.id} className={`gen-widget-slot slot-${i}`}>
                                        <iframe srcDoc={art.html} title={`Slot ${i}`} />
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>

        <SideDrawer 
            isOpen={drawerState.isOpen} 
            onClose={() => setDrawerState(s => ({...s, isOpen: false}))} 
            title={drawerState.title}
        >
            {drawerState.mode === 'code' && (
                <pre className="code-block"><code>{drawerState.data}</code></pre>
            )}
        </SideDrawer>
    </div>
  );
}

const rootElement = document.getElementById('root');
if (rootElement) {
  const root = ReactDOM.createRoot(rootElement);
  root.render(<App />);
