:root {
    --bg-deep: #050505;
    --bg-card: rgba(18, 18, 18, 0.8);
    --border: rgba(255, 255, 255, 0.1);
    --accent: #3b82f6;
    --accent-glow: rgba(59, 130, 246, 0.5);
    --text-p: #ffffff;
    --text-s: #94a3b8;
}

body, html, #root {
    margin: 0; padding: 0; width: 100vw; height: 100vh;
    background: var(--bg-deep); color: var(--text-p);
    font-family: 'Inter', sans-serif; overflow: hidden;
}

.immersive-app {
    width: 100%; height: 100%; position: relative;
}

/* --- Dashboard Styles --- */
.metaverse-dashboard {
    width: 100%; height: 100%;
    display: flex; flex-direction: column;
    background: radial-gradient(circle at top right, #0a0a1a, #050505);
}

.dashboard-nav {
    height: 70px; border-bottom: 1px solid var(--border);
    display: flex; align-items: center; justify-content: space-between;
    padding: 0 40px; backdrop-filter: blur(20px); z-index: 10;
}

.logo { font-weight: 800; letter-spacing: 4px; font-size: 1.2rem; }
.nav-links { display: flex; gap: 40px; }
.nav-links span { color: var(--text-s); font-size: 0.8rem; letter-spacing: 2px; cursor: pointer; transition: 0.3s; }
.nav-links span.active { color: var(--accent); text-shadow: 0 0 10px var(--accent-glow); }
.nav-links span:hover { color: #fff; }

.user-profile { display: flex; align-items: center; gap: 20px; }
.status { background: rgba(59, 130, 246, 0.1); color: var(--accent); padding: 4px 12px; border-radius: 4px; font-size: 0.7rem; border: 1px solid var(--accent); }
.exit-btn { background: transparent; border: 1px solid rgba(255, 255, 255, 0.2); color: #fff; padding: 8px 16px; border-radius: 4px; cursor: pointer; transition: 0.3s; }
.exit-btn:hover { background: #fff; color: #000; }

.dashboard-content {
    flex: 1; display: flex; padding: 20px; gap: 20px; overflow: hidden;
}

.sidebar-widgets {
    width: 320px; display: flex; flex-direction: column; gap: 20px;
}

.main-viewport {
    flex: 1; display: flex; flex-direction: column; gap: 20px;
}

.viewport-3d {
    flex: 2; background: #000; border-radius: 12px; border: 1px solid var(--border);
    position: relative; overflow: hidden;
}

.viewport-overlay {
    position: absolute; bottom: 20px; right: 20px; font-family: 'Roboto Mono', monospace; font-size: 0.7rem; color: var(--text-s);
}

.gen-widgets-preview {
    flex: 1; display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px;
}

.gen-widget-slot {
    background: var(--bg-card); border-radius: 12px; border: 1px solid var(--border);
    overflow: hidden; position: relative;
}

.gen-widget-slot iframe { width: 100%; height: 100%; border: none; }

.meta-widget {
    background: var(--bg-card); border: 1px solid var(--border); padding: 20px; border-radius: 12px;
}

.widget-header { font-size: 0.7rem; letter-spacing: 2px; color: var(--text-s); margin-bottom: 15px; display: flex; align-items: center; gap: 8px; }
.live-dot { width: 6px; height: 6px; background: #22c55e; border-radius: 50%; box-shadow: 0 0 8px #22c55e; }

/* --- Editor Styles --- */
.editor-layer { width: 100%; height: 100%; display: flex; flex-direction: column; }
.stage-container { flex: 1; display: flex; align-items: center; justify-content: center; overflow: hidden; padding: 40px; }

.empty-state { text-align: center; }
.empty-state h1 { font-size: 4rem; margin: 0; font-weight: 800; background: linear-gradient(to bottom, #fff, #444); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
.empty-state p { color: var(--text-s); letter-spacing: 4px; text-transform: uppercase; font-size: 0.8rem; }

