.artifact-card { flex: 1; background: var(--bg-card); border: 1px solid var(--border); border-radius: 16px; overflow: hidden; transition: 0.4s cubic-bezier(0.2, 0, 0, 1); cursor: pointer; }
.artifact-card:hover { transform: scale(1.02); border-color: var(--accent); }
