.artifact-card-inner { width: 100%; height: 100%; }
.artifact-iframe { width: 100%; height: 100%; border: none; }

.floating-input-container { position: absolute; bottom: 40px; left: 50%; transform: translateX(-50%); width: 100%; max-width: 600px; padding: 0 20px; }
.input-wrapper { background: rgba(18, 18, 18, 0.8); backdrop-filter: blur(20px); border: 1px solid var(--border); padding: 8px; border-radius: 16px; display: flex; gap: 10px; box-shadow: 0 10px 40px rgba(0,0,0,0.5); }
.input-wrapper input { flex: 1; background: transparent; border: none; color: #fff; padding: 12px 20px; font-size: 1rem; outline: none; }
