.send-button:hover { background: #2563eb; transform: translateY(-2px); }

.action-bar { position: absolute; bottom: 120px; left: 50%; transform: translateX(-50%); display: flex; gap: 10px; opacity: 0; pointer-events: none; transition: 0.3s; }
.action-bar.visible { opacity: 1; pointer-events: all; }
.action-bar button { background: rgba(255,255,255,0.05); color: #fff; border: 1px solid var(--border); padding: 8px 16px; border-radius: 8px; font-size: 0.8rem; cursor: pointer; display: flex; align-items: center; gap: 8px; transition: 0.3s; }
.action-bar button:hover { background: #fff; color: #000; }

